#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int main() {
    int N;
    scanf("%d", &N);
    int* C = (int*)malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d", &C[i]);
    }
    long long* dp = (long long*)malloc((N + 1) * sizeof(long long));
    dp[0] = 1;
    for (int i = 1; i <= N; i++) {
        dp[i] = (dp[i - 1] * i) % MOD;
    }
    long long ans = 0;
    for (int i = 0; i < N; i++) {
        long long temp = 1;
        for (int j = 0; j < N; j++) {
            if (i != j) {
                temp = (temp * (C[j] + 1)) % MOD;
            }
        }
        ans = (ans + temp) % MOD;
    }
    printf("%lld\n", ans);
    return 0;
}

